css:
/*【文刊·南风集】作者：易碎蝶*/

/*🍃←这个是可以调整的部分，以及用了【这个符号】*/

/* ====== 全局字体设置 ====== */
@import url("https://fontsapi.zeoseven.com/467/main/result.css");

body {
    font-family: "NanoOldSong-A";
    font-weight: normal;
}
/*———————— 移动端顶栏背景 ————————*/
#top-bar {
    position: fixed !important;  /* 改为固定定位适配移动端 */
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /* 全屏宽度 */
    height: 77px;  /* 适合移动端的顶部高度 */
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background:  url("https://i.postimg.cc/j2R32Jsg/Image-3285562948517834.png") no-repeat center / cover;  /* 使用cover适配屏幕 */

    /* 移动端适配定位 */
    top: 0px;
    left: 0px;
    right: 0px;
    bottom: 40px;

    /* 层级控制 */
    z-index: 5;
    pointer-events: auto;

    /* 移除动画相关属性 */
    transform: none !important;
    animation: none !important;
}



/* —————面板背景图———— */
.drawer-content {
  background-image: url('https://i.postimg.cc/NjFD55Md/Camera-1040g3k831g5kl3mshkd05n3u070kf9vbcfgk7lo.jpg'); /* 示例图片URL */
  background-size: cover; /* 图片覆盖整个元素 */
  background-position: center; /* 图片居中显示 */
  background-repeat: no-repeat; /* 图片不重复 */
  background-attachment: fixed; /* 固定背景图片 */
}

/*——————滑块——————*/

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 30px;
    height: 30px;
    background: transparent url('https://i.postimg.cc/L5K7F6QD/Image-3289822707588473.png') center/cover no-repeat;
    border: none;
    border-radius: 0;
    box-shadow: none;
    cursor: ew-resize;
    position: relative;
    z-index: 1;
}

/*——————最新消息箭头图标替换——————*/
/* ===== 隐藏原有字体图标 ===== */
.fa-chevron-right:before,
.fa-chevron-left:before,
.fa-arrow-right:before {
  content: "" !important;
  display: none !important; /* 双重保障隐藏图标 */
}

/* ===== 自定义箭头样式 ===== */
.fa-chevron-left,
.fa-chevron-right {
  display: inline-block;
  width: 80px;   /* 箭头图片宽度 */
  height: 25px;  /* 箭头图片高度 */
  background: center/contain no-repeat;
}

.fa-chevron-left {
  background-image: url('https://i.postimg.cc/zfRccrtj/Image-3285558123360218.png'); /* 左箭头URL */
}


.fa-chevron-right {
  background-image: url('https://i.postimg.cc/zfRccrtj/Image-3285558123360218.png'); /* 右箭头URL */
}

/* ===== 滑动计数器样式 ===== */
.swipes-counter {
  /* 文字样式 */
  color: var(--SmartThemeBodyColor);
  font-family: var(--mainFontFamily);
  font-size: 10px;
  font-weight: 540;

  /* 布局定位 */
  display: flex;
  justify-content: center;
  align-self: center;
  z-index: 3;

  /* 尺寸控制 */
  min-width: 0;
  height: var(--swipeCounterHeight); /* 高度变量 */
  padding: 0 50px;                 /* 水平内边距（右边箭头左右位置） */



  /* 间距控制 */
  margin: 
    var(--counter-vertical, 0)    /* 垂直间距，默认0 */
    var(--counter-horizonta, 0);  /* 水平间距，默认0 */
  margin-bottom: var(--swipeCounterMargin); /* 底部间距变量 */

  /* 备用定位方案 (需要时启用) */
  /* position: relative;
  left: var(--counter-left, 0);
  top: var(--counter-top, 0); */
}

/*——————装饰层——————*/
/* /* ==============================================
 * 1. 🍃装饰层模块
 * ==============================================*/
/* 🍃上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -112px; /* 上层装饰层【上下】(负值表示向上) */
  left: -0px; /* 上层装饰层【左右】 */
  width: 340px; /* 调整上层装饰层的【宽度/大小】 */
  height: 530px; /* 调整上层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/G2D2gWrn/Image-3279534925334783.png'); /* 替换为你的图片链接 - 上层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: -2; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}



/* 🍃下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -71px; /* 下层装饰层【上下】(负值表示向下) */
  right: -0px; /* 下层装饰层【左右】 */
  width: 340px; /* 调整下层装饰层的【宽度/大小】 */
  height: 282.6px; /* 调整下层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/q7SqLkPG/Image-3279510521457550.png'); /* 替换为你的图片链接 - 下层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: -4; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————🍃文本边距调整——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 🍃可独立调整的边距系统 */

    --top-padding:0rem; /* 气泡顶部留白 */
    --bottom-padding: 4rem; /* 气泡底部留白 */
    --left-padding: 0.5rem; /* 气泡左边距 */
    --right-padding: 0.7rem; /* 气泡右边距 */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    /* 最大宽度控制 */
    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

    /* 气泡视觉相关样式（可根据UI需求扩展） */
    /* background-color: #f0f0f0; */
    /* border-radius: 19px; */
}






/*——————气泡设置——————*/

/* ==============================================
 * 1.🍃 气泡容器模块
 * ==============================================*/
.mes {
  color: #363c39 !important; /* 深棕色 */
  z-index: -3;
  max-width: 340px;/*【🍃宽度】*/
  width: 400%;/*【🍃宽度，一般调整第一个就行，没效果再调整这个】*/
  margin: 140px auto 70px;/*【AI和用户的气泡距离】*/
  border-radius: 0px;
  /* 移除渐变背景和阴影 */
  background: url('https://i.postimg.cc/HLVjXJhx/Image-3279536687722475.png') repeat-y; /* 添加重复方向 */
  background-size: 100% auto; /* 保持宽度适配 */
  background-attachment: local; /* 确保滚动时背景同步 */
  transition: transform 0.2s ease; /* 移除阴影过渡 */
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; /* 强制移除所有阴影 */
}

/* ==============================================
 * 头像框层
 * ============================================== */

.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 48.9%;
  transform: translateX(-50%);
  z-index: -1;

  width: 70px;  
  height: 70px; 
  overflow: visible; 
}

/* 2. 🍃装饰框核心 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 75%;/* 【上下】 */
  left: 88%;/* 【左右】 */
  width: 330%;  /* 【框宽度】 */
  height: 250%; /* 【框高度】 */


  display: block;

  /* 头像框链接 */
  background-image: url('https://i.postimg.cc/Z5fCWPj2/Image-3279519470160859.png');
  background-size: 100% 100%;
  background-repeat: no-repeat;
  background-position: center;

  transform: translate(-50%, -50%);
  z-index: 1; 

}

.mesAvatarWrapper img {
  position: relative;
  z-index: -1; 
}

/* ==============================================
 * 2. 🍃头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -73px;           /* 【控制头像在气泡上方的位置】 */
  left: 61%;            /* 【调整头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 🍃基础尺寸 - 可自定义修改 */
  width: 107px;           /* 头像宽度 */
  height: 116px;          /* 头像高度 */


  /* 外观样式 */
  overflow: hidden;
  border: 0px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0);
  transition: all 0.3s ease;

  /* 旋转效果 */
  transform: rotate(0deg); /* 顺时针旋转 */
}

.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ==============================================
 * 4. 🍃楼层显示
 * ============================================== */
.mes .mesIDDisplay {

    position: fixed;  
    top: 200;           
    left: -188%;        /* 【楼层左右】 */
    transform: translateX(-50%); 
    z-index: 999;    
    margin-top: -146px; /* 【楼层上下】 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.0); /* 【这里可以填楼层显示的背景色，最后一个数字区调整透明度】 */
    border-radius: 4px;
    box-shadow: 90 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    z-index: 2;
    cursor: default;
    opacity: 0.9;
    font-size: calc(var(--mainFontSize) * 0.8);
    font-weight: 600;
    color: #777f7d; /* 【调整楼层显示的颜色】 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 1.9);
    font-weight: 600;
    text-align: center;
}
/* ==============================================
 * 5. 🍃基础信息位置调整【时间戳等】
 * ============================================== */

/* 消息块容器 */
.mes_block {
  position: relative;
  padding-top: 62px; /* 保持顶部留白 */
  overflow: visible; /* 确保子元素不被裁剪 */
}

/* 角色昵称颜色 */
.mes_block .ch_name {
  color: #777f7d !important; /* 纯黑色 */
  text-shadow: none !important; /* 移除可能存在的文字阴影 */
  -webkit-text-stroke: 0 !important; /* 移除文字描边 */
}

/* 时间戳纯白色 */
.timestamp {
  color: #777f7d !important; /* 纯白色 */
  opacity: 1 !important; /* 确保完全不透明 */
}

/* 角色名称 */
.mes_block .ch_name {
  position: relative;
  top: 0; /* 修正偏移量，避免过高 */
  left: 20px;/* 正值向右 */
  max-width: calc(100% - 105px); /* 保持宽度限制 */
  min-height: 0px;
  z-index: 10; /* 降低层级，确保不覆盖按钮 */
 font-size: 0.90em;
  font-weight: 300;
  letter-spacing: 0.9px;
}

/* 固定时间戳 */
.timestamp {
  color: #777f7d;
  position: absolute; /* 改为绝对定位 */
  top: -149.5px;         /* 距父容器顶部的距离 */
  left: -6px;          /* 固定在父容器左侧 */
  width: 100%;        /* 确保宽度不挤压 */
  pointer-events: none; /* 防止阻挡下方交互 */
  /* 新增字体样式 */
  font-size: 7px;     /* 设置字体大小（示例值） */
  font-weight: 900;    /* 设置字体粗细（示例值） */
}

/* 固定编辑按钮位置 */

/* 编辑按钮容器优化 */
.mes_buttons {
  position: relative;
  top: -21px; /*上下*/
  left: 73px;/*左右*/
  z-index: 30;
  padding: 20px; /* 增加内边距 */
  min-height: 36px; /* 确保最小高度 */
  box-sizing: border-box; /* 包含内边距 */
}


.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 5px;
    filter: drop-shadow(0px 0px 0px black);
    transition: 0.3s ease-in-out;

    /* 垂直位置控制 */
    position: relative;       /* 确保定位生效 */
    top: 0px;              /* 负数上移 | 正数下移 | 单位可用px/rem/vh等 */

    /* 水平位置控制 */
    right: -40px;            /* 负数右移 | 正数左移 | 单位可用px/rem/vw等 */
}

.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    /* 移除原阴影并添加白色阴影 */
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* 添加颜色设置为白色 */
    color: #777f7d !important;
}



/* ==============================================
 * 🕒 计时器 & 🔤 字符计数显示组件
 * ============================================== */

.mes {
  position: relative; /* 创建定位上下文 */
}

/* 通用样式 */
.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; /* 使用固定定位确保不被遮挡 */
  z-index: 2147483647; /* 最高层级 (32位整数最大值) */
  cursor: default;
  opacity: 1;
  font-size: calc(var(--mainFontSize) * 0.7);
  font-weight: 100;
  text-align: center;
  padding: 0px 0px;
  border-radius: 0px;
  background: rgba(30, 30, 30, 0.0); /* 半透明白色背景 */
  backdrop-filter: blur(0px); /* 毛玻璃效果 */
  box-shadow: 0 2px 8px rgba(0,0,0,0.0);

  /* 默认位置 - 顶部居中 */
  top: 240px;
  left: 50%;
  transform: translateX(-50%);

  /* 颜色变量 - 便于单独修改 */
  --timer-color: #777f7d;
  --counter-color: #777f7d;
}

/* 单独控制计时器 */
.mes .mes_timer {
  z-index: 2;
  /* 位置调整 */
  top: var(--timer-top, 11px);  /* 【🍃计时器上下】 */
  left: var(--timer-left, -182%);/*【🍃计时器左右】*/
  transform: translateX(var(--timer-translate, -50%));

  /* 颜色控制 */
  color: var(--timer-color, #777f7d);
}

/* 单独控制字符计数 */
.mes .tokenCounterDisplay {
  z-index: 2;
  /* 位置调整 */
  top: var(--counter-top, 26px); /* 【🍃字符上下】 */
  left: var(--counter-left, -198%);/* 【🍃字符左右】 */
  transform: translateX(var(--counter-translate, -0%));

  /* 颜色控制 */
  color: var(--counter-color, #777f7d);
}
/* ==============================================
 * 🧠 外显思维链位置与颜色调整
 * ============================================== */
/* 推理头部容器 - 南风集日间模式 */
.mes_reasoning_header {
  position: absolute;         /* 保持绝对定位 */
  z-index: 9999;              /* 确保顶层显示 */
  top: 115px;                 /* 距顶部距离 */
  left: 17%;                  /* 水平定位 */
  transform: translateX(-50%); /* 精确居中 */
  cursor: pointer;            /* 手型指针 */
  user-select: none;          /* 禁止文本选择 */
  font-size: calc(var(--mainFontSize) * 0.85); /* 响应式字体 */
  opacity: 0.9;               /* 轻微透明 */
  transition: all 0.3s ease;  /* 平滑过渡效果 */

  /* 南风集主题配色 */
  padding: 4px 10px;          /* 内边距 */
  background: rgba(255, 255, 255, 0.9); /* 90%透明纯白背景 */
  border-radius: 3px;         /* 圆角效果 */

  /* 三层古风描边效果 */
  box-shadow: 
    inset 1px 1px 2px rgba(117, 142, 125, 0.3), /* 内发光：柔绿色 */
    0 0 0 1px #fff,          /* 第一层：纯白描边 */
    0 0 0 2px #758e7d,       /* 第二层：主题绿描边 */
    0 0 0 3px #fff,          /* 第三层：纯白描边 */
    1px 2px 4px rgba(0, 0, 0, 0.1); /* 浅色外阴影 */
}

/* 悬停效果 - 竹叶舒展 */
.mes_reasoning_header:hover {
  background: rgba(245, 251, 245, 0.95); /* 悬停浅绿白背景 */
  box-shadow: 
    inset 1px 1px 3px rgba(117, 142, 125, 0.4), /* 强化内发光 */
    0 0 0 1px #fff,
    0 0 0 2px #5a6d5c,       /* 深绿色描边 */
    0 0 0 3px #fff,
    2px 3px 6px rgba(0, 0, 0, 0.15); /* 加深阴影 */
}

/* 标题文字 - 竹青色 */
.mes_reasoning_header_title {
  position: relative;
  display: inline-block;
  top: 0px;                   /* 垂直定位 */
  left: -9px;                 /* 水平微调 */
  color: #3a523c;             /* 深绿文字 */
  text-shadow: 0 1px 1px rgba(255, 255, 255, 0.8); /* 白色文字阴影 */
}

/* 推理主体 - 宣纸风格 */
.mes_reasoning {
  position: relative;         
  top: -160px;                /* 垂直位置 */
  display: block;
  margin: 135px 0;            /* 外边距 */

  /* 南风集主题样式 */
  border-left: 3px solid #758e7d; /* 左侧装饰：主题绿 */
  color: #2c3e2e;             /* 文字：墨绿色 */
  background: 
    linear-gradient(rgba(255, 255, 255, 0.35), rgba(255, 255, 255, 0.5)), /* 白色渐变遮罩 */
    url('https://i.postimg.cc/1XczsDfW/Image-3279604514325171.png') center/cover; /* 南风背景图 */

  border-radius: 0 8px 8px 0; /* 右侧圆角 */
  box-shadow: 
    inset 2px 2px 4px rgba(117, 142, 125, 0.2), /* 内阴影：柔绿光晕 */
    0 2px 6px rgba(0, 0, 0, 0.08); /* 浅色外投影 */
  padding: 15px;              /* 内边距 */
  backdrop-filter: blur(1px); /* 轻微背景模糊 */
}


/* ===== 基础图标样式 ===== */
.drawer-icon:not(.openIcon) { 
  opacity: 0.4 !important; 
}

/* 通用图标替换样式 */
.drawer-icon {
  background: url('https://i.postimg.cc/dt1nfFDy/Image-3285543275052602.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

.drawer-icon::before {
  display: none !important;
}

/* ===== 特定图标覆盖 ===== */
/* AI响应配置 */
#leftNavDrawerIcon {
  background-image: url('https://i.postimg.cc/Hk8zptwW/Image-3285540233700217.png') !important;

}

/* API连接 */
#API-status-top::before { display: none !important; }
#API-status-top {
  background: url('https://i.postimg.cc/gkT4F76B/Image-3285541872527987.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
  font-size: 0 !important;
}

/* AI回复格式化 */
.drawer-icon.fa-font::before { display: none !important; }
.drawer-icon.fa-font {
  background: ur1('https://i.postimg.cc/dt1nfFDy/Image-3285543275052602.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 世界信息 */
#WIDrawerIcon::before { display: none !important; }
#WIDrawerIcon {
  background: url('https://i.postimg.cc/fW5B5yWs/Image-3285545729172833.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 用户设置 */
.drawer-icon.fa-user::before { display: none !important; }
.drawer-icon.fa-user {
  background: url('https://i.postimg.cc/2SgHvtkB/Image-3285550013439064.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 背景更换 */
