/*——————复选——————*/
.title::after {
  background: linear-gradient(to right, 
    transparent, 
    #758E7D 40%,  /* 主色调-南风绿(标题装饰线) */
    #9AB0A4,      /* 辅助色-浅竹青(过渡色) */
    transparent
  );
  box-shadow: none; /* 保持无阴影 */
}

/* 复选框基底 - 日间模式 */
input[type='checkbox'] {
  background: rgba(255, 255, 255, 0.9); /* 90%透明纯白基底 */
  box-shadow: 
    inset 2px 2px 4px rgba(0, 0, 0, 0.4),  /* 浅色内阴影(立体感) */
    3px 3px 4px rgba(0, 0, 0, 0.45),        /* 浅色投影(悬浮感) */
    0 0 0 1px #FFFFFF,                      /* 第一层-纯白描边 */
    0 0 0 2px #758E7D,                      /* 第二层-南风绿描边 */
    0 0 0 3px #FFFFFF;                      /* 第三层-纯白描边 */

}

/* 悬停状态 */
input[type='checkbox']:hover {
  background: rgba(255, 255, 255, 0.95); /* 95%透明白(悬停反馈) */
  box-shadow: 
    inset -2px -2px 4px rgba(0, 0, 0, 0.08), 
    3px 3px 5px rgba(0, 0, 0, 0.08),
    0 0 0 1px #FFFFFF,                      
    0 0 0 2px #758E7D,
    0 0 0 3px #FFFFFF;
}

/* 选中状态 */
input[type='checkbox']:checked {
  background: #758E7D; /* 南风绿基底(选中态) */
  box-shadow: 
    inset -2px -2px 4px rgba(0, 0, 0, 0.1), 
    2px 2px 4px rgba(0, 0, 0, 0.1),
    0 0 0 1px #FFFFFF,                       /* 保持三层描边结构 */
    0 0 0 2px #FFFFFF,                       /* 白色内圈(增强对比) */
    0 0 0 px #758E7D;                       /* 外圈南风绿(视觉聚焦) */
}
/* 桃花图标 - 纯白色 */
input[type='checkbox']:checked::after {
  content: '-';        /* 桃花符号 */
  font-size: 1.5em;
  position: absolute;
  top: 40%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #FFF;         /* 纯白色图标 */
  text-shadow: 0 0 3px rgba(0,0,0,0.5); /* 黑色微光阴影 */
}

/* 确保原生勾选隐藏 */
input[type="checkbox"]::before {
  content: none !important;
}

