/* ===== 轻拟态下拉框系统 - 桃花劫主题（夜间模式）===== */
/* ===== 下拉选择框样式 - 南风集主题 ===== */
.drawer-content select {
  /* 核心轻拟态效果 - 日间模式 */
  background: rgba(255, 255, 255, 0.9) url('') no-repeat left top; /* 90%透明纯白底 */
  background-size: 425px auto;
  backdrop-filter: blur(0px);

  /* 立体阴影系统 - 三层描边效果 */
  box-shadow:
    inset 1px 3px 2px rgba(0, 0, 0, 0.05), /* 左上角内陷阴影 - 轻微阴影增加深度 */
    inset -1px 0px 3px rgba(0, 0, 0, 0.05), /* 内阴影 - 增强深度感 */
    0 0 0 1px #ffffff,          /* 第一层纯白描边 */
    0 0 0 2px #758e7d,          /* 第二层绿色描边 - 南风集主题色 */
    0 0 0 4px #ffffff,          /* 第三层纯白描边 */
    3px 3px 8px rgba(0, 0, 0, 0.1); /* 右下角悬浮感阴影 - 增强立体感 */

  color: #3a4a40; /* 深绿色文字 - 与绿色描边协调 */
  border: 0px solid transparent;
  border-radius: 4px;
  padding-left: 10px;
}

/* 悬停状态 */
.drawer-content select:hover {
  box-shadow:
    inset 1px 1px 4px rgba(0, 0, 0, 0.07),
    inset -1px -1px 3px rgba(0, 0, 0, 0.07),
    0 0 0 1px #ffffff,
    0 0 0 2px #8aa394,          /* 稍亮的绿色描边 */
    0 0 0 3px #ffffff,
    4px 4px 10px rgba(0, 0, 0, 0.15); /* 更强的悬浮感阴影 */
}

/* 聚焦状态 */
.drawer-content select:focus {
  box-shadow:
    inset 1px 1px 4px rgba(0, 0, 0, 0.1),
    inset -1px -1px 4px rgba(0, 0, 0, 0.1),
    0 0 0 1px #ffffff,
    0 0 0 2px #9db7a8,          /* 更亮的绿色描边 */
    0 0 0 3px #ffffff,
    4px 4px 12px rgba(0, 0, 0, 0.2),
    0 0 0 2px rgba(117, 142, 125, 0.3); /* 绿色聚焦光晕 */
}

/* 选项样式 */
.drawer-content select option {
  background: rgba(255, 255, 255, 0.95); /* 95%透明纯白背景 */
  color: #3a4a40; /* 深绿色文字 */
}

/* ===== 输入框样式 - 南风集主题 ===== */
input:not([type="file" i], [type="image" i], [type="checkbox" i], [type="radio" i]) {
  /* 基底样式 */
  background: rgba(255, 255, 255, 0.7) url('') no-repeat center center / cover;
  border: 1px solid #e0e0e0; /* 浅灰色边框 */
  border-radius: 4px;
  padding: 0.5rem 0.8rem;
  transition: all 0.25s ease;
  color: #3a4a40; /* 深绿色文字 */
  font-size: 0.6rem;
  height: 1.4rem;

  /* 三层描边 - 南风集主题 */
  box-shadow: 
    inset 2px 2px 4px rgba(0,0,0,0.05),   /* 左上角内陷阴影 */
    0 0 0 1px #ffffff,                    /* 第一层纯白描边 */
    0 0 0 2px #758e7d,                    /* 第二层绿色描边 */
    0 0 0 3px #ffffff,                    /* 第三层纯白描边 */
    2px 2px 6px rgba(0,0,0,0.1);         /* 右下角悬浮感阴影 */
}

/* 聚焦状态 */
input:focus {
  outline: none;
  transform: translateY(-1px);
  border-color: #c0d0c0; /* 浅绿色边框 */
  box-shadow: 
    inset 3px 3px 5px rgba(0,0,0,0.08),
    0 0 0 1px #ffffff,
    0 0 0 2px #9db7a8,  /* 亮绿色描边 */
    0 0 0 3px #ffffff,
    3px 3px 8px rgba(0,0,0,0.15);
}

/* 悬停状态 */
input:hover {
  background: rgba(255, 255, 255, 0.95) url('') no-repeat center center / cover; 
  border-color: #a8b8a8; /* 浅绿色边框 */
  box-shadow: 
    inset 2px 2px 5px rgba(0,0,0,0.07),
    0 0 0 1px #ffffff,
    0 0 0 2px #8aa394,  /* 中等绿色描边 */
    0 0 0 3px #ffffff,
    3px 3px 7px rgba(0,0,0,0.12);
}

/* 禁用状态 */
input:disabled {
  background: rgba(250, 250, 250, 0.9) url('') no-repeat center center / cover; 
  color: #a0a8a0; /* 灰绿色文字 */
  cursor: not-allowed;
  border-color: #e0e0e0;
  box-shadow: 
    inset 1px 1px 3px rgba(0,0,0,0.05),
    0 0 0 1px #ffffff,
    0 0 0 2px #b0c0b0,  /* 浅绿色描边 */
    0 0 0 3px #ffffff,
    1px 1px 4px rgba(0,0,0,0.08);
}

